<script setup lang="ts">import { computed, onMounted, ref } from 'vue'; import { createItem, listCategories } from '../api/catalog'; import { useCatalogSearch } from '../catalog/useCatalogSearch'; import type { CategoryNode, ItemInput } from '../catalog/catalogModels'; import StPageHeader from '../components/StPageHeader.vue'; import ItemSearchResults from '../components/catalog/ItemSearchResults.vue'; import ItemForm from '../components/catalog/ItemForm.vue'; import ItemDetailView from './ItemDetailView.vue'; const props=defineProps<{role:string}>(); const search=useCatalogSearch(),creating=ref(false),selectedId=ref<string>(),categories=ref<CategoryNode[]>([]),error=ref(''); const canWrite=computed(()=>props.role!=='VIEWER'); onMounted(async()=>categories.value=await listCategories()); async function save(data:ItemInput){try{const item=await createItem(data);creating.value=false;selectedId.value=item.id}catch(e){error.value=(e as {detail?:string;code?:string}).detail??(e as {code?:string}).code??'保存失败'}}</script>
<template><section><StPageHeader title="物品目录" description="按名称或条码快速查找"><template v-if="canWrite" #actions><button @click="creating=true">创建物品</button></template></StPageHeader><label class="search-label">搜索物品<input v-model="search.query.value" type="search" aria-label="搜索物品" /></label><p v-if="search.error.value||error" role="alert">{{ search.error.value||error }}</p><ItemForm v-if="creating" :categories="categories" @save="save"/><ItemDetailView v-else-if="selectedId" :item-id="selectedId" :role="role"/><ItemSearchResults v-else :items="search.results.value" :searched="Boolean(search.query.value.trim())" @select="selectedId=$event.id"/></section></template>
